import{_ as d,o as a,c as r,a4 as e}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"第二章 中学课程","description":"","frontmatter":{"title":"第二章 中学课程","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter2.md","filePath":"study/teacher-cert/education-knowledge/chapter2.md","lastUpdated":null}'),h={name:"study/teacher-cert/education-knowledge/chapter2.md"};function o(l,t,i,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第二章-中学课程" tabindex="-1">第二章 中学课程 <a class="header-anchor" href="#第二章-中学课程" aria-label="Permalink to &quot;第二章 中学课程&quot;">​</a></h1><blockquote><p>本章考情：选择+简答为主，约 8-12 分 重点：课程类型、新课改、课程编制</p></blockquote><hr><h2 id="_2-1-课程概述-🔴🔴" tabindex="-1">2.1 课程概述 🔴🔴 <a class="header-anchor" href="#_2-1-课程概述-🔴🔴" aria-label="Permalink to &quot;2.1 课程概述 🔴🔴&quot;">​</a></h2><h3 id="课程的词源" tabindex="-1">课程的词源 <a class="header-anchor" href="#课程的词源" aria-label="Permalink to &quot;课程的词源&quot;">​</a></h3><ul><li><strong>中国</strong>：宋代朱熹&quot;宽着期限，紧着课程&quot; — &quot;课程&quot;一词最早出现 🔴</li><li><strong>西方</strong>：斯宾塞《什么知识最有价值》首次将&quot;课程&quot;用作教育学的专门术语 🔴</li></ul><h3 id="课程类型-🔴🔴🔴" tabindex="-1">课程类型 🔴🔴🔴 <a class="header-anchor" href="#课程类型-🔴🔴🔴" aria-label="Permalink to &quot;课程类型 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分类标准</th><th>类型</th><th>特点</th><th>代表/举例</th></tr></thead><tbody><tr><td>组织方式</td><td>学科课程 🔴</td><td>按学科逻辑组织，强调知识体系</td><td>赫尔巴特、六艺</td></tr><tr><td></td><td>活动课程</td><td>以儿童活动为中心</td><td>杜威 🔴</td></tr><tr><td></td><td>综合课程</td><td>打破学科界限，融合多学科</td><td>STS课程、科学课</td></tr><tr><td>修习方式</td><td>必修课程</td><td>全体学生必须修</td><td>国家课程</td></tr><tr><td></td><td>选修课程</td><td>学生自主选择</td><td>校本选修</td></tr><tr><td>管理主体</td><td>国家课程 🔴</td><td>国家统一制定</td><td>统编教材</td></tr><tr><td></td><td>地方课程</td><td>省级教育部门制定</td><td>地方文化课</td></tr><tr><td></td><td>校本课程 🔴</td><td>学校自主开发</td><td>学校特色课</td></tr><tr><td>呈现方式</td><td>显性课程</td><td>有计划有组织</td><td>课表上的课</td></tr><tr><td></td><td>隐性课程 🔴🔴</td><td>以间接、内隐方式影响</td><td>校风、师生关系、校园文化</td></tr></tbody></table><p><strong>辨析题高频</strong> 🔴🔴：</p><ul><li>&quot;隐性课程不是课程&quot; → ❌ 隐性课程也是课程，只是以间接方式影响学生</li><li>&quot;活动课程优于学科课程&quot; → ❌ 各有优缺点，应互相补充</li></ul><hr><h2 id="_2-2-课程理论流派-🔴" tabindex="-1">2.2 课程理论流派 🔴 <a class="header-anchor" href="#_2-2-课程理论流派-🔴" aria-label="Permalink to &quot;2.2 课程理论流派 🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>流派</th><th>代表人物</th><th>核心主张</th><th>优缺点</th></tr></thead><tbody><tr><td>学科中心课程论</td><td>赫尔巴特、斯宾塞、布鲁纳</td><td>以学科知识为中心，按逻辑体系组织</td><td>系统但不贴近生活</td></tr><tr><td>学生中心课程论</td><td>杜威 🔴</td><td>以儿童兴趣和活动为中心</td><td>贴近学生但不够系统</td></tr><tr><td>社会中心课程论</td><td>布拉梅尔德</td><td>以社会问题为中心</td><td>关注社会但窄化教育</td></tr></tbody></table><hr><h2 id="_2-3-课程编制-🔴🔴" tabindex="-1">2.3 课程编制 🔴🔴 <a class="header-anchor" href="#_2-3-课程编制-🔴🔴" aria-label="Permalink to &quot;2.3 课程编制 🔴🔴&quot;">​</a></h2><h3 id="课程目标" tabindex="-1">课程目标 <a class="header-anchor" href="#课程目标" aria-label="Permalink to &quot;课程目标&quot;">​</a></h3><p><strong>布鲁姆教育目标分类</strong> 🔴🔴：</p><table tabindex="0"><thead><tr><th>领域</th><th>层次（由低到高）</th></tr></thead><tbody><tr><td>认知领域</td><td>知识→理解→应用→分析→综合→评价</td></tr><tr><td>情感领域</td><td>接受→反应→形成价值观念→组织价值体系→价值体系个性化</td></tr><tr><td>动作技能领域</td><td>知觉→模仿→操作→准确→连贯→习惯化</td></tr></tbody></table><h3 id="课程内容-🔴🔴🔴" tabindex="-1">课程内容 🔴🔴🔴 <a class="header-anchor" href="#课程内容-🔴🔴🔴" aria-label="Permalink to &quot;课程内容 🔴🔴🔴&quot;">​</a></h3><p><strong>三级层次</strong>：</p><table tabindex="0"><thead><tr><th>层次</th><th>含义</th><th>特点</th></tr></thead><tbody><tr><td>课程计划 🔴</td><td>国家教育行政部门制定的教学工作的指导性文件</td><td>宏观，规定学科设置和顺序</td></tr><tr><td>课程标准 🔴🔴</td><td>每门学科的教学指导文件（原称&quot;教学大纲&quot;）</td><td>中观，是编写教材和教学的依据</td></tr><tr><td>教材 🔴</td><td>教师和学生使用的教学材料</td><td>微观，课程标准的具体化</td></tr></tbody></table><p><strong>辨析题</strong> 🔴：</p><ul><li>&quot;课程标准就是教材&quot; → ❌ 课程标准是教学指导文件，教材是具体教学材料</li><li>&quot;教材就是教科书&quot; → ❌ 教材包含教科书，也包含其他教学资源</li></ul><h3 id="课程评价-🔴" tabindex="-1">课程评价 🔴 <a class="header-anchor" href="#课程评价-🔴" aria-label="Permalink to &quot;课程评价 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>提出者</th><th>核心观点</th></tr></thead><tbody><tr><td>目标评价模式</td><td>泰勒 🔴</td><td>以目标为中心评价</td></tr><tr><td>目的游离评价模式</td><td>斯克里文</td><td>评价应关注实际效果而非预定目标</td></tr><tr><td>CIPP 模式</td><td>斯塔弗尔比姆</td><td>背景→输入→过程→成果</td></tr></tbody></table><hr><h2 id="_2-4-新课改-🔴🔴🔴" tabindex="-1">2.4 新课改 🔴🔴🔴 <a class="header-anchor" href="#_2-4-新课改-🔴🔴🔴" aria-label="Permalink to &quot;2.4 新课改 🔴🔴🔴&quot;">​</a></h2><h3 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h3><p><strong>&quot;以人为本&quot;</strong> 🔴🔴 — 一切为了每一位学生的发展</p><h3 id="课程结构改革-🔴🔴" tabindex="-1">课程结构改革 🔴🔴 <a class="header-anchor" href="#课程结构改革-🔴🔴" aria-label="Permalink to &quot;课程结构改革 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>改革内容</th><th>具体表现</th></tr></thead><tbody><tr><td>整体设置九年一贯制</td><td>小学→初中一体化</td></tr><tr><td>小学阶段</td><td>综合课程为主</td></tr><tr><td>初中阶段</td><td>分科课程与综合课程相结合 🔴</td></tr><tr><td>高中阶段</td><td>分科课程为主</td></tr><tr><td>新增课程</td><td>综合实践活动课 🔴🔴（必修）</td></tr></tbody></table><p><strong>综合实践活动课</strong> 🔴🔴：</p><ul><li>内容：研究性学习、社区服务与社会实践、劳动与技术教育、信息技术教育</li><li>性质：必修课程</li><li>特点：自主性、开放性、实践性</li></ul><h3 id="学习方式改革-🔴🔴" tabindex="-1">学习方式改革 🔴🔴 <a class="header-anchor" href="#学习方式改革-🔴🔴" aria-label="Permalink to &quot;学习方式改革 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>传统方式</th><th>新方式</th><th>特点</th></tr></thead><tbody><tr><td>被动接受</td><td>自主学习</td><td>主动、独立</td></tr><tr><td>独立完成</td><td>合作学习</td><td>互动、团队</td></tr><tr><td>机械记忆</td><td>探究学习 🔴</td><td>问题、过程、开放</td></tr></tbody></table><h3 id="课程管理改革-🔴" tabindex="-1">课程管理改革 🔴 <a class="header-anchor" href="#课程管理改革-🔴" aria-label="Permalink to &quot;课程管理改革 🔴&quot;">​</a></h3><p><strong>三级课程管理</strong>：国家课程 → 地方课程 → 校本课程</p><h3 id="简答题必背-🔴🔴" tabindex="-1">简答题必背 🔴🔴 <a class="header-anchor" href="#简答题必背-🔴🔴" aria-label="Permalink to &quot;简答题必背 🔴🔴&quot;">​</a></h3><p><strong>新课改的具体目标</strong>（口诀：方平的节目有结）：</p><ol><li>改变课程功能 — 知识传授→引导学生学会学习、学会做人</li><li>改变课程结构 — 学科本位→均衡性、综合性、选择性</li><li>改变课程内容 — 难繁偏旧→联系生活和社会</li><li>改变课程实施 — 死记硬背→主动参与、乐于探究</li><li>改变课程评价 — 甄别选拔→促进发展</li><li>改变课程管理 — 集中统一→三级管理</li></ol><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>口诀/要点</th></tr></thead><tbody><tr><td>课程类型</td><td>学科/活动/综合，必修/选修，国家/地方/校本，显性/隐性</td></tr><tr><td>隐性课程判断</td><td>校风、师生关系、班级氛围、校园文化</td></tr><tr><td>课程内容三层次</td><td>课程计划（宏观）→课程标准（中观）→教材（微观）</td></tr><tr><td>新课改六目标</td><td>方平的节目有结</td></tr><tr><td>综合实践活动</td><td>研社劳信（研究性学习、社区服务、劳动技术、信息技术）</td></tr></tbody></table>',43)])])}const q=d(h,[["render",o]]);export{c as __pageData,q as default};
